def gen(rng, size):
    import string
    n = rng.randint(1, max(1, min(100, size)))
    mode = rng.randint(0, 4)
    if mode == 0:
        w = ''.join(rng.choice(string.ascii_uppercase) for _ in range(n))
    elif mode == 1:
        w = ''.join(rng.choice(string.ascii_lowercase) for _ in range(n))
    elif mode == 2:
        w = rng.choice(string.ascii_uppercase) + ''.join(rng.choice(string.ascii_lowercase) for _ in range(n - 1))
    else:
        w = ''.join(rng.choice(string.ascii_letters) for _ in range(n))
    return [w]

